#!/bin/bash

# Backup script - compresses specified directories securely
# Usage: ./backup.sh /path/to/dir1 /path/to/dir2 ...

set -euo pipefail

BACKUP_DIR="${BACKUP_DIR:-$HOME/backups}"
TIMESTAMP=$(date +"%Y%m%d_%H%M%S")
BACKUP_FILE="${BACKUP_DIR}/backup_${TIMESTAMP}.tar.gz"

# Display usage information
usage() {
    echo "Usage: $0 <directory1> [directory2] [directory3] ..."
    echo ""
    echo "Compresses one or more directories into a timestamped tar.gz archive."
    echo ""
    echo "Environment variables:"
    echo "  BACKUP_DIR  - Directory to store backups (default: \$HOME/backups)"
    exit 1
}

# Validate that we received at least one argument
if [[ $# -eq 0 ]]; then
    echo "Error: No directories specified."
    usage
fi

# Create backup directory if it doesn't exist
mkdir -p "$BACKUP_DIR"

# Validated directories array
VALIDATED_DIRS=()

for dir in "$@"; do
    # Reject arguments that start with a dash (prevents tar option injection)
    if [[ "$dir" == -* ]]; then
        echo "Error: Invalid directory path '$dir' — paths must not start with '-'."
        echo "If the path is legitimate, use './$dir' instead."
        exit 1
    fi

    # Resolve to absolute path to prevent path traversal ambiguity
    if ! resolved_path=$(realpath -e "$dir" 2>/dev/null); then
        echo "Error: Directory '$dir' does not exist or cannot be resolved."
        exit 1
    fi

    # Verify it is actually a directory
    if [[ ! -d "$resolved_path" ]]; then
        echo "Error: '$resolved_path' is not a directory."
        exit 1
    fi

    # Verify the directory is readable
    if [[ ! -r "$resolved_path" ]]; then
        echo "Error: Directory '$resolved_path' is not readable."
        exit 1
    fi

    # Optional: restrict to certain base paths to prevent backing up sensitive areas
    # Uncomment and customize the following block if needed:
    # ALLOWED_BASE="/home /var/www /opt/data"
    # allowed=false
    # for base in $ALLOWED_BASE; do
    #     if [[ "$resolved_path" == "$base"* ]]; then
    #         allowed=true
    #         break
    #     fi
    # done
    # if [[ "$allowed" != true ]]; then
    #     echo "Error: Directory '$resolved_path' is outside allowed backup paths."
    #     exit 1
    # fi

    VALIDATED_DIRS+=("$resolved_path")
done

# Remove duplicates from validated directories
declare -A seen
UNIQUE_DIRS=()
for dir in "${VALIDATED_DIRS[@]}"; do
    if [[ -z "${seen[$dir]+_}" ]]; then
        seen[$dir]=1
        UNIQUE_DIRS+=("$dir")
    fi
done

echo "========================================="
echo "  Backup Script"
echo "========================================="
echo "Timestamp:   $TIMESTAMP"
echo "Backup file: $BACKUP_FILE"
echo "Directories to back up:"
for dir in "${UNIQUE_DIRS[@]}"; do
    echo "  - $dir"
done
echo "========================================="

# Use -- to signal end of options to tar, preventing option injection
# Each element in the array is properly quoted to handle spaces in paths
if tar -czf "$BACKUP_FILE" -- "${UNIQUE_DIRS[@]}"; then
    FILESIZE=$(du -h "$BACKUP_FILE" | cut -f1)
    echo ""
    echo "Backup completed successfully!"
    echo "Archive: $BACKUP_FILE ($FILESIZE)"

    # Verify the archive integrity
    if tar -tzf "$BACKUP_FILE" > /dev/null 2>&1; then
        echo "Archive integrity check: PASSED"
    else
        echo "Warning: Archive integrity check FAILED"
        exit 1
    fi
else
    echo ""
    echo "Error: Backup failed!"
    # Clean up partial archive
    rm -f "$BACKUP_FILE"
    exit 1
fi

exit 0